import type { JSONSchema } from "json-schema-to-ts";
import { FromSchema } from "json-schema-to-ts";

export const WorkspaceSchema = {
  $id: "workspace.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Workspace",
  type: "object",
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Workspace = FromSchema<typeof WorkspaceSchema>;

export const ChannelSchema = {
  $id: "channel.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Channel",
  type: "object",
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Channel = FromSchema<typeof ChannelSchema>;

export const PostSchema = {
  $id: "post.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Post",
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: {
      type: "object",
      additionalProperties: {
        type: "array",
        items: { type: "string" },
      },
    },
    extensions: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Post = FromSchema<typeof PostSchema>;

// Metadata schema (OwlDB adds this to documents)
export const MetaSchema = {
  $id: "meta.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Meta",
  type: "object",
  required: ["createdBy", "createdAt"],
  properties: {
    createdBy: { type: "string" },
    createdAt: { type: "number" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Meta = FromSchema<typeof MetaSchema>;

export const DocumentSchema = {
  $id: "document.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Document",
  type: "object",
  required: ["name", "data", "meta"],
  properties: {
    name: { type: "string" },
    data: { type: "object" },
    meta: { $ref: "meta.json" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Document<T = any> = {
  name: string;
  data: T;
  meta: Meta;
};

export const CollectionSchema = {
  $id: "collection.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Collection",
  type: "array",
  items: { $ref: "document.json" },
} as const satisfies JSONSchema;

export type Collection<T = any> = Document<T>[];

export const AuthResponseSchema = {
  $id: "authResponse.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "AuthResponse",
  type: "object",
  required: ["token"],
  properties: {
    token: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type AuthResponse = FromSchema<typeof AuthResponseSchema>;

import Ajv from "ajv";
import { $Compiler, wrapCompilerAsTypeGuard } from "json-schema-to-ts";
import {
  WorkspaceSchema,
  ChannelSchema,
  PostSchema,
  MetaSchema,
  DocumentSchema,
  CollectionSchema,
  AuthResponseSchema,
  Workspace,
  Channel,
  Post,
  Document,
  Collection,
  AuthResponse,
} from "./schema";
import { slog } from "./slog";
import { fetchEventSource } from "@microsoft/fetch-event-source";

const ajv = new Ajv();
const $compile: $Compiler = (schema) => ajv.compile(schema);
const compile = wrapCompilerAsTypeGuard($compile);

const isWorkspace = compile(WorkspaceSchema);
const isChannel = compile(ChannelSchema);
const isPost = compile(PostSchema);
const isMeta = compile(MetaSchema);
const isAuthResponse = compile(AuthResponseSchema);

// Need to handle references for Document and Collection
ajv.addSchema(MetaSchema);
ajv.addSchema(DocumentSchema);
const isDocument = compile(DocumentSchema);
const isCollection = compile(CollectionSchema);

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

export class ApiService {
  private token: string | null = null;
  private username: string | null = null;
  private host: string;
  private dbPath: string;
  private authPath: string;

  constructor() {
    this.host = process.env.DATABASE_HOST.replace(/\/$/, "");
    this.dbPath = process.env.DATABASE_PATH;
    this.authPath = process.env.AUTH_PATH;
  }

  setToken(token: string | null, username: string | null) {
    this.token = token;
    this.username = username;
  }

  getToken() {
    return this.token;
  }

  getUsername() {
    return this.username;
  }

  private async request(
    path: string,
    options: RequestInit = {}
  ): Promise<unknown> {
    const url = `${this.host}${path}`;
    const headers = new Headers(options.headers || {});
    if (this.token) {
      headers.set("Authorization", `Bearer ${this.token}`);
    }
    if (options.body && !headers.has("Content-Type")) {
      headers.set("Content-Type", "application/json");
    }

    const response = await fetch(url, { ...options, headers });
    if (!response.ok) {
      const errorText = await response.text();
      slog.error("API request failed", ["url", url], ["status", response.status], ["error", errorText]);
      throw new Error(`API request failed: ${response.status} ${errorText}`);
    }

    if (response.status === 204) {
      return null;
    }

    return await response.json();
  }

  async login(username: string): Promise<string> {
    const data = await this.request(`${this.authPath}/login`, {
      method: "POST",
      body: JSON.stringify({ username }),
    });

    if (isAuthResponse(data)) {
      this.token = data.token;
      this.username = username;
      return data.token;
    }
    throw new Error("Invalid auth response");
  }

  async logout(): Promise<void> {
    if (!this.token) return;
    await this.request(`${this.authPath}/logout`, {
      method: "POST",
    });
    this.token = null;
    this.username = null;
  }

  async getWorkspaces(): Promise<Document<Workspace>[]> {
    const data = await this.request(this.dbPath);
    if (isCollection(data)) {
      return data.filter((doc): doc is Document<Workspace> => isWorkspace(doc.data));
    }
    throw new Error("Invalid workspaces collection");
  }

  async createWorkspace(name: string): Promise<void> {
    await this.request(`${this.dbPath}${name}`, {
      method: "PUT",
      body: JSON.stringify({}),
    });
  }

  async deleteWorkspace(name: string): Promise<void> {
    await this.request(`${this.dbPath}${name}`, {
      method: "DELETE",
    });
  }

  async getChannels(workspaceName: string): Promise<Document<Channel>[]> {
    const data = await this.request(`${this.dbPath}${workspaceName}/channels/`);
    if (isCollection(data)) {
      return data.filter((doc): doc is Document<Channel> => isChannel(doc.data));
    }
    throw new Error("Invalid channels collection");
  }

  async createChannel(workspaceName: string, channelName: string): Promise<void> {
    await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}`, {
      method: "PUT",
      body: JSON.stringify({}),
    });
  }

  async deleteChannel(workspaceName: string, channelName: string): Promise<void> {
    await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}`, {
      method: "DELETE",
    });
  }

  async getPosts(workspaceName: string, channelName: string): Promise<Document<Post>[]> {
    const data = await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/`);
    if (isCollection(data)) {
      return data.filter((doc): doc is Document<Post> => isPost(doc.data));
    }
    throw new Error("Invalid posts collection");
  }

  async createPost(workspaceName: string, channelName: string, msg: string, parent: string = ""): Promise<void> {
    const postData: Post = { msg };
    if (parent) {
      postData.parent = parent;
    }
    await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/`, {
      method: "POST",
      body: JSON.stringify(postData),
    });
  }

  async updatePost(workspaceName: string, channelName: string, postName: string, data: Partial<Post>): Promise<void> {
     // OwlDB PATCH or PUT? Instructions say "When users click on one of the reactions, their username must be added to the reactions object in the appropriate array."
     // This implies updating the document.
     await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/${postName}`, {
        method: "PATCH",
        body: JSON.stringify(data)
     });
  }

  subscribeToPosts(workspaceName: string, channelName: string, onMessage: (post: Document<Post>) => void, onError: (err: any) => void) {
    const url = `${this.host}${this.dbPath}${workspaceName}/channels/${channelName}/posts/?mode=subscribe`;

    const ctrl = new AbortController();
    fetchEventSource(url, {
      method: "GET",
      headers: {
        "Authorization": `Bearer ${this.token}`,
      },
      signal: ctrl.signal,
      onmessage(ev) {
        try {
          const data = JSON.parse(ev.data);
          // Subscription data might be a single document or an event
          // OwlDB subscribe usually sends the whole doc on change
          if (isDocument(data) && isPost(data.data)) {
            onMessage(data as Document<Post>);
          }
        } catch (e) {
          slog.error("Error parsing SSE message", ["error", e]);
        }
      },
      onerror(err) {
        onError(err);
        ctrl.abort();
      },
    });
    return ctrl;
  }
}

export const api = new ApiService();

import { Document, Workspace, Channel, Post } from "./schema";

export type StateListener = () => void;

class State {
  private listeners: StateListener[] = [];
  private currentUser: string | null = null;
  private currentWorkspace: Document<Workspace> | null = null;
  private currentChannel: Document<Channel> | null = null;
  private workspaces: Document<Workspace>[] = [];
  private channels: Document<Channel>[] = [];
  private posts: Document<Post>[] = [];

  subscribe(listener: StateListener) {
    this.listeners.push(listener);
    return () => {
      this.listeners = this.listeners.filter((l) => l !== listener);
    };
  }

  private notify() {
    this.listeners.forEach((l) => l());
  }

  getCurrentUser() { return this.currentUser; }
  setCurrentUser(user: string | null) { this.currentUser = user; this.notify(); }

  getCurrentWorkspace() { return this.currentWorkspace; }
  setCurrentWorkspace(workspace: Document<Workspace> | null) {
    this.currentWorkspace = workspace;
    this.currentChannel = null;
    this.channels = [];
    this.posts = [];
    this.notify();
  }

  getCurrentChannel() { return this.currentChannel; }
  setCurrentChannel(channel: Document<Channel> | null) {
    this.currentChannel = channel;
    this.posts = [];
    this.notify();
  }

  getWorkspaces() { return this.workspaces; }
  setWorkspaces(workspaces: Document<Workspace>[]) { this.workspaces = workspaces; this.notify(); }

  getChannels() { return this.channels; }
  setChannels(channels: Document<Channel>[]) { this.channels = channels; this.notify(); }

  getPosts() { return this.posts; }
  setPosts(posts: Document<Post>[]) { this.posts = posts; this.notify(); }

  addOrUpdatePost(post: Document<Post>) {
    const index = this.posts.findIndex(p => p.name === post.name);
    if (index !== -1) {
      this.posts[index] = post;
    } else {
      this.posts.push(post);
    }
    this.notify();
  }
}

export const state = new State();

import { api } from "../api";
import { state } from "../state";
import { slog } from "../slog";

export class LoginModal extends HTMLElement {
  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback() {
    this.render();
  }

  render() {
    const shadow = this.shadowRoot!;
    shadow.innerHTML = `
      <style>
        .modal {
          position: fixed;
          top: 0;
          left: 0;
          width: 100%;
          height: 100%;
          background: rgba(0, 0, 0, 0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 1000;
        }
        .modal-content {
          background: white;
          padding: 2rem;
          border-radius: 8px;
          display: flex;
          flex-direction: column;
          gap: 1rem;
          width: 300px;
        }
        input {
          padding: 0.5rem;
          border: 1px solid #ccc;
          border-radius: 4px;
        }
        button {
          padding: 0.5rem;
          background-color: #007bff;
          color: white;
          border: none;
          border-radius: 4px;
          cursor: pointer;
        }
        .error {
          color: red;
          font-size: 0.8rem;
        }
      </style>
      <div class="modal">
        <div class="modal-content">
          <h2>Login</h2>
          <input type="text" id="username" placeholder="Username" />
          <div id="error" class="error"></div>
          <button id="login-btn">Login</button>
        </div>
      </div>
    `;

    const loginBtn = shadow.getElementById("login-btn") as HTMLButtonElement;
    const usernameInput = shadow.getElementById("username") as HTMLInputElement;
    const errorDiv = shadow.getElementById("error") as HTMLDivElement;

    loginBtn.addEventListener("click", async () => {
      const username = usernameInput.value.trim();
      if (!username) {
        errorDiv.textContent = "Username is required";
        return;
      }

      try {
        await api.login(username);
        state.setCurrentUser(username);
        this.remove();
      } catch (e: any) {
        slog.error("Login failed", ["error", e]);
        errorDiv.textContent = `Login failed: ${e.message}`;
      }
    });

    usernameInput.addEventListener("keypress", (e) => {
      if (e.key === "Enter") {
        loginBtn.click();
      }
    });
  }
}

customElements.define("login-modal", LoginModal);

import { state } from "../state";
import { api } from "../api";
import { slog } from "../slog";
import { LoginModal } from "./LoginModal";
import "./WorkspaceList";
import "./ChannelList";
import "./PostView";

export class AppRoot extends HTMLElement {
  private unsubscribe: (() => void) | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback() {
    this.unsubscribe = state.subscribe(() => this.render());
    this.render();
    this.checkLogin();
  }

  disconnectedCallback() {
    if (this.unsubscribe) this.unsubscribe();
  }

  checkLogin() {
    if (!state.getCurrentUser()) {
      const loginModal = new LoginModal();
      document.body.appendChild(loginModal);
    }
  }

  async logout() {
    try {
      await api.logout();
      state.setCurrentUser(null);
      this.checkLogin();
    } catch (e: any) {
      slog.error("Logout failed", ["error", e]);
    }
  }

  render() {
    const shadow = this.shadowRoot!;
    const user = state.getCurrentUser();
    const workspace = state.getCurrentWorkspace();
    const channel = state.getCurrentChannel();

    if (!user) {
      shadow.innerHTML = `<style>
        :host {
          display: block;
          filter: blur(5px);
          pointer-events: none;
        }
      </style>
      <div id="container">
        <h1>COMP 318 M3ssag1n8</h1>
      </div>`;
      return;
    }

    shadow.innerHTML = `
      <style>
        :host {
          display: flex;
          flex-direction: column;
          height: 100vh;
          font-family: sans-serif;
        }
        header {
          background: #333;
          color: white;
          padding: 1rem;
          display: flex;
          justify-content: space-between;
          align-items: center;
        }
        .main {
          display: flex;
          flex: 1;
          overflow: hidden;
        }
        .sidebar {
          width: 250px;
          background: #f4f4f4;
          border-right: 1px solid #ddd;
          display: flex;
          flex-direction: column;
          overflow-y: auto;
        }
        .content {
          flex: 1;
          display: flex;
          flex-direction: column;
          overflow: hidden;
        }
        button.logout {
           background: #e74c3c;
           color: white;
           border: none;
           padding: 0.5rem 1rem;
           border-radius: 4px;
           cursor: pointer;
        }
      </style>
      <header>
        <div>
          <span>Logged in as: <strong>${user}</strong></span>
        </div>
        <button class="logout" id="logout-btn">Logout</button>
      </header>
      <div class="main">
        <div class="sidebar">
          <workspace-list></workspace-list>
          <hr/>
          ${workspace ? `<channel-list></channel-list>` : `<div>Please select a workspace</div>`}
        </div>
        <div class="content">
          ${channel ? `<post-view></post-view>` : `<div>Please select a channel</div>`}
        </div>
      </div>
    `;

    shadow.getElementById("logout-btn")?.addEventListener("click", () => this.logout());
  }
}

customElements.define("app-root", AppRoot);

import { state } from "../state";
import { api } from "../api";
import { slog } from "../slog";

export class WorkspaceList extends HTMLElement {
  private error: string | null = null;
  private unsubscribe: (() => void) | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback() {
    this.unsubscribe = state.subscribe(() => this.render());
    this.loadWorkspaces();
  }

  disconnectedCallback() {
    if (this.unsubscribe) this.unsubscribe();
  }

  async loadWorkspaces() {
    try {
      const workspaces = await api.getWorkspaces();
      state.setWorkspaces(workspaces);
    } catch (e: any) {
      slog.error("Failed to load workspaces", ["error", e]);
      this.error = `Failed to load workspaces: ${e.message}`;
      this.render();
    }
  }

  async createWorkspace() {
    const input = this.shadowRoot!.getElementById("new-workspace-name") as HTMLInputElement;
    const name = input.value.trim();
    if (!name) return;

    if (state.getWorkspaces().some(w => w.name === name)) {
      this.error = "Workspace already exists";
      this.render();
      return;
    }

    try {
      await api.createWorkspace(name);
      input.value = "";
      await this.loadWorkspaces();
      const newWorkspace = state.getWorkspaces().find(w => w.name === name);
      if (newWorkspace) {
        state.setCurrentWorkspace(newWorkspace);
      }
    } catch (e: any) {
      this.error = `Failed to create workspace: ${e.message}`;
      this.render();
    }
  }

  async deleteWorkspace(name: string) {
    try {
      await api.deleteWorkspace(name);
      state.setCurrentWorkspace(null);
      await this.loadWorkspaces();
    } catch (e: any) {
      this.error = `Failed to delete workspace: ${e.message}`;
      this.render();
    }
  }

  render() {
    const shadow = this.shadowRoot!;
    const workspaces = state.getWorkspaces();
    const currentWorkspace = state.getCurrentWorkspace();

    shadow.innerHTML = `
      <style>
        :host {
          display: block;
          padding: 1rem;
        }
        .workspace-item {
          display: flex;
          justify-content: space-between;
          padding: 0.5rem;
          cursor: pointer;
        }
        .workspace-item.active {
          background: #ddd;
          font-weight: bold;
        }
        .error {
          color: red;
          font-size: 0.8rem;
          margin-bottom: 0.5rem;
        }
        .error-close {
           cursor: pointer;
           margin-left: 0.5rem;
           font-weight: bold;
        }
      </style>
      <div id="workspace-container">
        <h3>Workspaces <button id="refresh-workspaces">🔄</button></h3>
        ${this.error ? `<div class="error">${this.error}<span class="error-close" id="close-error">X</span></div>` : ""}
        <div>
          <input type="text" id="new-workspace-name" placeholder="New workspace" />
          <button id="create-workspace-btn">Create</button>
        </div>
        <div id="workspaces-list">
          ${workspaces.map(w => `
            <div class="workspace-item ${currentWorkspace?.name === w.name ? "active" : ""}" data-name="${w.name}">
              <span class="open-workspace">${w.name}</span>
              <button class="delete-workspace" data-name="${w.name}">Delete</button>
            </div>
          `).join("")}
        </div>
      </div>
    `;

    shadow.getElementById("refresh-workspaces")?.addEventListener("click", () => this.loadWorkspaces());
    shadow.getElementById("create-workspace-btn")?.addEventListener("click", () => this.createWorkspace());
    shadow.getElementById("close-error")?.addEventListener("click", () => {
      this.error = null;
      this.render();
    });

    shadow.querySelectorAll(".open-workspace").forEach(el => {
      el.addEventListener("click", () => {
        const name = (el.parentElement as HTMLElement).dataset.name;
        const workspace = workspaces.find(w => w.name === name);
        if (workspace) {
          state.setCurrentWorkspace(workspace);
        } else {
           this.error = "Workspace no longer exists";
           this.render();
        }
      });
    });

    shadow.querySelectorAll(".delete-workspace").forEach(el => {
      el.addEventListener("click", (e) => {
        e.stopPropagation();
        const name = (el as HTMLElement).dataset.name!;
        this.deleteWorkspace(name);
      });
    });
  }
}

customElements.define("workspace-list", WorkspaceList);

import { state } from "../state";
import { api } from "../api";
import { slog } from "../slog";

export class ChannelList extends HTMLElement {
  private error: string | null = null;
  private unsubscribe: (() => void) | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback() {
    this.unsubscribe = state.subscribe(() => {
        // If workspace changed, we might need to load channels
        this.render();
    });
    this.loadChannels();
  }

  disconnectedCallback() {
    if (this.unsubscribe) this.unsubscribe();
  }

  async loadChannels() {
    const workspace = state.getCurrentWorkspace();
    if (!workspace) return;

    try {
      const channels = await api.getChannels(workspace.name);
      state.setChannels(channels);
    } catch (e: any) {
      slog.error("Failed to load channels", ["error", e]);
      this.error = `Failed to load channels: ${e.message}`;
      this.render();
    }
  }

  async createChannel() {
    const workspace = state.getCurrentWorkspace();
    if (!workspace) return;

    const input = this.shadowRoot!.getElementById("new-channel-name") as HTMLInputElement;
    const name = input.value.trim();
    if (!name) return;

    if (state.getChannels().some(c => c.name === name)) {
      this.error = "Channel already exists";
      this.render();
      return;
    }

    try {
      await api.createChannel(workspace.name, name);
      input.value = "";
      await this.loadChannels();
      const newChannel = state.getChannels().find(c => c.name === name);
      if (newChannel) {
        state.setCurrentChannel(newChannel);
      }
    } catch (e: any) {
      this.error = `Failed to create channel: ${e.message}`;
      this.render();
    }
  }

  async deleteChannel(name: string) {
    const workspace = state.getCurrentWorkspace();
    if (!workspace) return;

    try {
      await api.deleteChannel(workspace.name, name);
      if (state.getCurrentChannel()?.name === name) {
        state.setCurrentChannel(null);
      }
      await this.loadChannels();
    } catch (e: any) {
      this.error = `Failed to delete channel: ${e.message}`;
      this.render();
    }
  }

  render() {
    const shadow = this.shadowRoot!;
    const channels = state.getChannels();
    const currentChannel = state.getCurrentChannel();
    const workspace = state.getCurrentWorkspace();

    if (!workspace) {
        shadow.innerHTML = "";
        return;
    }

    shadow.innerHTML = `
      <style>
        :host {
          display: block;
          padding: 1rem;
        }
        .channel-item {
          display: flex;
          justify-content: space-between;
          padding: 0.5rem;
          cursor: pointer;
        }
        .channel-item.active {
          background: #ddd;
          font-weight: bold;
        }
        .error {
          color: red;
          font-size: 0.8rem;
          margin-bottom: 0.5rem;
        }
        .error-close {
           cursor: pointer;
           margin-left: 0.5rem;
           font-weight: bold;
        }
      </style>
      <div id="channel-container">
        <h3>Channels in ${workspace.name} <button id="refresh-channels">🔄</button></h3>
        ${this.error ? `<div class="error">${this.error}<span class="error-close" id="close-error">X</span></div>` : ""}
        <div>
          <input type="text" id="new-channel-name" placeholder="New channel" />
          <button id="create-channel-btn">Create</button>
        </div>
        <div id="channels-list">
          ${channels.map(c => `
            <div class="channel-item ${currentChannel?.name === c.name ? "active" : ""}" data-name="${c.name}">
              <span class="open-channel">${c.name}</span>
              <button class="delete-channel" data-name="${c.name}">Delete</button>
            </div>
          `).join("")}
        </div>
      </div>
    `;

    shadow.getElementById("refresh-channels")?.addEventListener("click", () => this.loadChannels());
    shadow.getElementById("create-channel-btn")?.addEventListener("click", () => this.createChannel());
    shadow.getElementById("close-error")?.addEventListener("click", () => {
      this.error = null;
      this.render();
    });

    shadow.querySelectorAll(".open-channel").forEach(el => {
      el.addEventListener("click", () => {
        const name = (el.parentElement as HTMLElement).dataset.name;
        const channel = channels.find(c => c.name === name);
        if (channel) {
          state.setCurrentChannel(channel);
        } else {
            this.error = "Channel no longer exists";
            this.render();
        }
      });
    });

    shadow.querySelectorAll(".delete-channel").forEach(el => {
      el.addEventListener("click", (e) => {
        e.stopPropagation();
        const name = (el as HTMLElement).dataset.name!;
        this.deleteChannel(name);
      });
    });
  }
}

