import { state } from "../state";
import { api } from "../api";
import { slog } from "../slog";
import { Document, Post } from "../schema";
import "./PostItem";
import "./PostInput";

export class PostView extends HTMLElement {
  private unsubscribe: (() => void) | null = null;
  private sseCtrl: AbortController | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback() {
    this.unsubscribe = state.subscribe(() => this.render());
    this.loadPosts();
    this.subscribe();
  }

  disconnectedCallback() {
    if (this.unsubscribe) this.unsubscribe();
    if (this.sseCtrl) this.sseCtrl.abort();
  }

  async loadPosts() {
    const workspace = state.getCurrentWorkspace();
    const channel = state.getCurrentChannel();
    if (!workspace || !channel) return;

    try {
      const posts = await api.getPosts(workspace.name, channel.name);
      state.setPosts(posts);
    } catch (e: any) {
      slog.error("Failed to load posts", ["error", e]);
    }
  }

  subscribe() {
    const workspace = state.getCurrentWorkspace();
    const channel = state.getCurrentChannel();
    if (!workspace || !channel) return;

    if (this.sseCtrl) this.sseCtrl.abort();

    this.sseCtrl = api.subscribeToPosts(
      workspace.name,
      channel.name,
      (post) => {
        state.addOrUpdatePost(post);
      },
      (err) => {
        slog.error("SSE Error", ["error", err]);
      }
    );
  }

  render() {
    const shadow = this.shadowRoot!;
    const channel = state.getCurrentChannel();
    const posts = state.getPosts();

    if (!channel) {
      shadow.innerHTML = "";
      return;
    }

    // Sort posts by creation time
    const sortedPosts = [...posts].sort((a, b) => a.meta.createdAt - b.meta.createdAt);

    shadow.innerHTML = `
      <style>
        :host {
          display: flex;
          flex-direction: column;
          height: 100%;
          overflow: hidden;
        }
        .posts-container {
          flex: 1;
          overflow-y: auto;
          padding: 1rem;
        }
        .channel-header {
           padding: 1rem;
           border-bottom: 1px solid #ddd;
           background: #eee;
        }
      </style>
      <div class="channel-header">
        <h2># ${channel.name}</h2>
      </div>
      <div class="posts-container" id="posts-container">
        <div id="posts-list"></div>
      </div>
      <div id="input-container">
        <post-input id="main-input"></post-input>
      </div>
    `;

    const postsList = shadow.getElementById("posts-list")!;
    this.renderHierarchy(sortedPosts, "", postsList, 0);
  }

  renderHierarchy(posts: Document<Post>[], parentPath: string, container: HTMLElement, level: number) {
    const children = posts.filter(p => (p.data.parent || "") === parentPath);
    children.forEach(post => {
      const postItem = document.createElement("post-item") as any;
      postItem.post = post;
      postItem.level = level;
      container.appendChild(postItem);

      // Document path in OwlDB for this post is its name? 
      // Instructions say: "this field must be a string that gives the document path (this is the path within the database, so it should not include the database name)."
      // Workspace: /workspaceName
      // Channel: /workspaceName/channels/channelName
      // Post: /workspaceName/channels/channelName/posts/postName
      const workspace = state.getCurrentWorkspace()!;
      const channel = state.getCurrentChannel()!;
      const postPath = `${workspace.name}/channels/${channel.name}/posts/${post.name}`;

      this.renderHierarchy(posts, postPath, container, level + 1);
    });
  }
}

