import { state } from "../state";
import { api } from "../api";
import { slog } from "../slog";

export class PostInput extends HTMLElement {
  private parentPath: string = "";
  private parentElement: HTMLElement | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback() {
    this.render();
  }

  setParent(path: string, element: HTMLElement) {
    this.parentPath = path;
    this.parentElement = element;
    this.render();
  }

  clearParent() {
    this.parentPath = "";
    this.parentElement = null;
    const postView = document.querySelector("app-root")?.shadowRoot?.querySelector("post-view")?.shadowRoot;
    const inputContainer = postView?.getElementById("input-container");
    if (inputContainer) {
      inputContainer.appendChild(this);
    }
    this.render();
  }

  insertText(prefix: string, suffix: string = "") {
    const textarea = this.shadowRoot!.getElementById("post-msg") as HTMLTextAreaElement;
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const selection = text.substring(start, end);
    const replacement = prefix + selection + suffix;
    textarea.value = text.substring(0, start) + replacement + text.substring(end);
    textarea.focus();
    textarea.selectionStart = start + prefix.length;
    textarea.selectionEnd = end + prefix.length;
  }

  async submitPost() {
    const textarea = this.shadowRoot!.getElementById("post-msg") as HTMLTextAreaElement;
    const msg = textarea.value.trim();
    if (!msg) return;

    const workspace = state.getCurrentWorkspace();
    const channel = state.getCurrentChannel();
    if (!workspace || !channel) return;

    try {
      await api.createPost(workspace.name, channel.name, msg, this.parentPath);
      textarea.value = "";
      if (this.parentPath) {
        this.clearParent();
      }
    } catch (e: any) {
      slog.error("Failed to post", ["error", e]);
    }
  }

  render() {
    const shadow = this.shadowRoot!;
    shadow.innerHTML = `
      <style>
        :host {
          display: block;
          padding: 1rem;
          background: #f9f9f9;
          border-top: 1px solid #ddd;
        }
        textarea {
          width: 100%;
          height: 80px;
          padding: 0.5rem;
          box-sizing: border-box;
          border: 1px solid #ccc;
          border-radius: 4px;
          resize: vertical;
        }
        .toolbar {
          margin-bottom: 0.5rem;
          display: flex;
          gap: 0.5rem;
          flex-wrap: wrap;
        }
        button {
          padding: 0.3rem 0.6rem;
          cursor: pointer;
        }
        .submit-area {
          margin-top: 0.5rem;
          display: flex;
          justify-content: flex-end;
          gap: 0.5rem;
        }
        .post-btn {
          background: #28a745;
          color: white;
          border: none;
          border-radius: 4px;
        }
      </style>
      <div class="toolbar">
        <button id="bold-btn" title="Bold"><strong>B</strong></button>
        <button id="italic-btn" title="Italic"><em>I</em></button>
        <button id="link-btn" title="Link">Link</button>
        <button class="emoji-btn" data-emoji=":smile:"><iconify-icon icon="fluent-emoji:smiling-face-with-smiling-eyes"></iconify-icon></button>
        <button class="emoji-btn" data-emoji=":frown:"><iconify-icon icon="fluent-emoji:frowning-face"></iconify-icon></button>
        <button class="emoji-btn" data-emoji=":like:"><iconify-icon icon="fluent-emoji:thumbs-up"></iconify-icon></button>
        <button class="emoji-btn" data-emoji=":celebrate:"><iconify-icon icon="fluent-emoji:party-popper"></iconify-icon></button>
      </div>
      <textarea id="post-msg" placeholder="${this.parentPath ? "Write a reply..." : "Write a new post..."}"></textarea>
      <div class="submit-area">
        ${this.parentPath ? `<button id="cancel-reply">Cancel</button>` : ""}
        <button class="post-btn" id="post-btn">Post</button>
      </div>
    `;

    shadow.getElementById("bold-btn")?.addEventListener("click", () => this.insertText("**", "**"));
    shadow.getElementById("italic-btn")?.addEventListener("click", () => this.insertText("*", "*"));
    shadow.getElementById("link-btn")?.addEventListener("click", () => this.insertText("[", "](url)"));
    shadow.querySelectorAll(".emoji-btn").forEach(el => {
      el.addEventListener("click", () => this.insertText((el as HTMLElement).dataset.emoji!));
    });

    shadow.getElementById("post-btn")?.addEventListener("click", () => this.submitPost());
    shadow.getElementById("cancel-reply")?.addEventListener("click", () => this.clearParent());

    const textarea = shadow.getElementById("post-msg") as HTMLTextAreaElement;
    textarea.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        this.submitPost();
      }
    });
  }
}

