async createPost(workspaceName: string, channelName: string, msg: string, parent: string = ""): Promise<void> {
  const postData: Post = { msg };
  if (parent) {
    postData.parent = parent;
  }
  await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/`, {
    method: "POST",
    body: JSON.stringify(postData),
  });
}

async updatePost(workspaceName: string, channelName: string, postName: string, data: Partial<Post>): Promise<void> {
   // OwlDB PATCH or PUT? Instructions say "When users click on one of the reactions, their username must be added to the reactions object in the appropriate array."
   // This implies updating the document.
   await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/${postName}`, {
      method: "PATCH",
      body: JSON.stringify(data)
   });
}

subscribeToPosts(workspaceName: string, channelName: string, onMessage: (post: Document<Post>) => void, onError: (err: any) => void) {
  const url = `${this.host}${this.dbPath}${workspaceName}/channels/${channelName}/posts/?mode=subscribe`;

  const ctrl = new AbortController();
  fetchEventSource(url, {
    method: "GET",
    headers: {
      "Authorization": `Bearer ${this.token}`,
    },
    signal: ctrl.signal,
    onmessage: (ev) => {
      try {
        const data = JSON.parse(ev.data);
        // Subscription data might be a single document or an event
        // OwlDB subscribe usually sends the whole doc on change
        if (data && typeof data === 'object' && 'data' in data && isPost(data.data)) {
          onMessage(data as Document<Post>);
        }
      } catch (e) {
        slog.error("Error parsing SSE message", ["error", e]);
      }
    },
    onerror: (err) => {
      onError(err);
      ctrl.abort();
    },
  });
  return ctrl;
}

