subscribeToPosts(workspaceName: string, channelName: string, onMessage: (post: Document<Post>) => void, onError: (err: any) => void) {
  const url = `${this.host}${this.dbPath}${workspaceName}/channels/${channelName}/posts/?mode=subscribe`;

  const ctrl = new AbortController();
  fetchEventSource(url, {
    method: "GET",
    headers: {
      "Authorization": `Bearer ${this.token}`,
    },
    signal: ctrl.signal,
    onmessage(ev) {
      try {
        const data = JSON.parse(ev.data);
        // Subscription data might be a single document or an event
        // OwlDB subscribe usually sends the whole doc on change
        if (isDocument(data) && isPost(data.data)) {
          onMessage(data as Document<Post>);
        }
      } catch (e) {
        slog.error("Error parsing SSE message", ["error", e]);
      }
    },
    onerror(err) {
      onError(err);
      ctrl.abort();
    },
  });
  return ctrl;
}

