import Ajv from "ajv";
import { slog } from "./slog";
import { fetchEventSource } from "@microsoft/fetch-event-source";

console.log("ONE FILE START");

// Schemas
const WorkspaceSchema = { type: "object", additionalProperties: true };
const ChannelSchema = { type: "object", additionalProperties: true };
const PostSchema = {
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: { type: "object", additionalProperties: { type: "array", items: { type: "string" } } },
  },
  additionalProperties: true,
};
const AuthResponseSchema = {
  type: "object",
  required: ["token"],
  properties: { token: { type: "string" } },
  additionalProperties: true,
};

const ajv = new Ajv();
const isWorkspace = ajv.compile(WorkspaceSchema);
const isChannel = ajv.compile(ChannelSchema);
const isPost = ajv.compile(PostSchema);
const isAuthResponse = ajv.compile(AuthResponseSchema);

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

// API
class ApiService {
  private token: string | null = null;
  private host: string = process.env.DATABASE_HOST.replace(/\/$/, "");
  private dbPath: string = process.env.DATABASE_PATH;
  private authPath: string = process.env.AUTH_PATH;

  async login(username: string) {
    const res = await fetch(`${this.host}${this.authPath}/login`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username }),
    });
    const data = await res.json();
    if (isAuthResponse(data)) {
      this.token = data.token;
      return data.token;
    }
    throw new Error("Login failed");
  }

  async logout() {
    if (!this.token) return;
    await fetch(`${this.host}${this.authPath}/logout`, {
      method: "POST",
      headers: { "Authorization": `Bearer ${this.token}` },
    });
    this.token = null;
  }
}
const api = new ApiService();

// State
let currentUser: string | null = null;

// Components
class LoginModal extends HTMLElement {
  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }
  connectedCallback() {
    this.shadowRoot!.innerHTML = `
      <div id="modal" style="position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:1000">
        <div style="background:white;padding:20px;border-radius:8px">
          <h2>Login</h2>
          <input id="username" type="text" placeholder="Username" />
          <button id="login-btn">Login</button>
        </div>
      </div>
    `;
    this.shadowRoot!.getElementById("login-btn")!.addEventListener("click", async () => {
      const username = (this.shadowRoot!.getElementById("username") as HTMLInputElement).value.trim();
      if (!username) return;
      try {
        await api.login(username);
        currentUser = username;
        this.remove();
        document.body.appendChild(new AppRoot());
      } catch (e) {
        console.error(e);
      }
    });
  }
}
customElements.define("login-modal", LoginModal);

class AppRoot extends HTMLElement {
  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }
  connectedCallback() {
    this.shadowRoot!.innerHTML = `
      <header style="background:#333;color:white;padding:10px;display:flex;justify-content:space-between">
        <span>Logged in as: <strong id="user-display">${currentUser}</strong></span>
        <button id="logout-btn">Logout</button>
      </header>
    `;
    this.shadowRoot!.getElementById("logout-btn")!.addEventListener("click", async () => {
      await api.logout();
      currentUser = null;
      this.remove();
      document.body.appendChild(new LoginModal());
    });
  }
}
customElements.define("app-root", AppRoot);

