  document.body.appendChild(app);
}

document.addEventListener("DOMContentLoaded", () => {
  main();
});

import Ajv from "ajv";
import { $Compiler, wrapCompilerAsTypeGuard } from "json-schema-to-ts";
import {
  WorkspaceSchema,
  ChannelSchema,
  PostSchema,
  AuthResponseSchema,
  Workspace,
  Channel,
  Post,
  Document,
} from "./schema";
import { slog } from "./slog";
import { fetchEventSource } from "@microsoft/fetch-event-source";

const ajv = new Ajv();
const $compile: $Compiler = (schema) => ajv.compile(schema);
const compile = wrapCompilerAsTypeGuard($compile);

const isWorkspace = compile(WorkspaceSchema);
const isChannel = compile(ChannelSchema);
const isPost = compile(PostSchema);
const isAuthResponse = compile(AuthResponseSchema);

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

export class ApiService {
  private token: string | null = null;
  private username: string | null = null;
  private host: string;
  private dbPath: string;
  private authPath: string;

  constructor() {
    this.host = (process.env.DATABASE_HOST || "").replace(/\/$/, "");
    this.dbPath = process.env.DATABASE_PATH || "";
    this.authPath = process.env.AUTH_PATH || "";
  }

  setToken(token: string | null, username: string | null) {
    this.token = token;
    this.username = username;
  }

  private async request(
    path: string,
    options: RequestInit = {}
  ): Promise<unknown> {
    const url = `${this.host}${path}`;
    const headers = new Headers(options.headers || {});
    if (this.token) {
      headers.set("Authorization", `Bearer ${this.token}`);
    }
    if (options.body && !headers.has("Content-Type")) {
      headers.set("Content-Type", "application/json");
    }

    const response = await fetch(url, { ...options, headers });
    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`API request failed: ${response.status} ${errorText}`);
    }

    if (response.status === 204) {
      return null;
    }

    return await response.json();
  }

  async login(username: string): Promise<string> {
    const data = await this.request(`${this.authPath}/login`, {
      method: "POST",
      body: JSON.stringify({ username }),
    });

    if (isAuthResponse(data)) {
      this.token = data.token;
      this.username = username;
      return data.token;
    }
    throw new Error("Invalid auth response");
  }

  async logout(): Promise<void> {
    if (!this.token) return;
    await this.request(`${this.authPath}/logout`, {
      method: "POST",
    });
    this.token = null;
    this.username = null;
  }

  async getWorkspaces(): Promise<Document<Workspace>[]> {
    const data = (await this.request(this.dbPath)) as any[];
    return data.filter((doc) => isWorkspace(doc.data)) as Document<Workspace>[];
  }

  async createWorkspaceWithData(name: string, data: any): Promise<void> {
    await this.request(`${this.dbPath}${name}`, {
      method: "PUT",
      body: JSON.stringify(data),
    });
  }

  async deleteWorkspace(name: string): Promise<void> {
    await this.request(`${this.dbPath}${name}`, {
      method: "DELETE",
    });
  }

  async getChannels(workspaceName: string): Promise<Document<Channel>[]> {
    const data = (await this.request(`${this.dbPath}${workspaceName}/channels/`)) as any[];
    return data.filter((doc) => isChannel(doc.data)) as Document<Channel>[];
  }

  async createChannel(workspaceName: string, channelName: string): Promise<void> {
    await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}`, {
      method: "PUT",
      body: JSON.stringify({}),
    });
  }

  async deleteChannel(workspaceName: string, channelName: string): Promise<void> {
    await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}`, {
      method: "DELETE",
    });
  }

  async getPosts(workspaceName: string, channelName: string): Promise<Document<Post>[]> {
    const data = (await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/`)) as any[];
    return data.filter((doc) => isPost(doc.data)) as Document<Post>[];
  }

  async createPost(workspaceName: string, channelName: string, msg: string, parent: string = ""): Promise<void> {
    const postData: Post = { msg };
    if (parent) {
      postData.parent = parent;
    }
    await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/`, {
      method: "POST",
      body: JSON.stringify(postData),
    });
  }

  async updatePost(workspaceName: string, channelName: string, postName: string, data: Partial<Post>): Promise<void> {
     await this.request(`${this.dbPath}${workspaceName}/channels/${channelName}/posts/${postName}`, {
        method: "PATCH",
        body: JSON.stringify(data)
     });
  }

  subscribeToPosts(workspaceName: string, channelName: string, onMessage: (post: Document<Post>) => void, onError: (err: any) => void) {
    const url = `${this.host}${this.dbPath}${workspaceName}/channels/${channelName}/posts/?mode=subscribe`;

    const ctrl = new AbortController();
    fetchEventSource(url, {
      method: "GET",
      headers: {
        "Authorization": `Bearer ${this.token}`,
      },
      signal: ctrl.signal,
      onmessage: (ev) => {
        try {
          const data = JSON.parse(ev.data);
          if (data && typeof data === 'object' && 'data' in data && isPost(data.data)) {
            onMessage(data as Document<Post>);
          }
        } catch (e) {
          slog.error("Error parsing SSE message", ["error", e]);
        }
      },
      onerror: (err) => {
        onError(err);
        ctrl.abort();
      },
    });
    return ctrl;
  }
}

export const api = new ApiService();

